import React, { useState } from "react";
import Footer from "./Footer";

const Faq = () => {
  const [openIndex, setOpenIndex] = useState(null);

  const toggleAccordion = (index) => {
    setOpenIndex(openIndex === index ? null : index);
  };
  return (
    <>
      <main className="main__content_wrapper">
        {/* Start breadcrumb section */}
        <section className="breadcrumb__section breadcrumb__bg">
          <div className="container">
            <div className="row row-cols-1">
              <div className="col">
                <div className="breadcrumb__content text-center">
                  <h1 className="breadcrumb__content--title text-white mb-25">
                    Frequently Asked Questions
                  </h1>
                  <ul className="breadcrumb__content--menu d-flex justify-content-center">
                    <li className="breadcrumb__content--menu__items">
                      <a className="text-white" href="index.html">
                        Home
                      </a>
                    </li>
                    <li className="breadcrumb__content--menu__items">
                      <span className="text-white">FAQ</span>
                    </li>
                  </ul>
                </div>
              </div>
            </div>
          </div>
        </section>
        {/* End breadcrumb section */}
        {/* faq page section start */}
        <section className="faq__section section--padding">
          <div className="container">
            <div className="faq__section--inner">
              <div
                className="face__step one border-bottom"
                id="accordionExample"
              >
                <h2 className="face__step--title h3 mb-30">
                  Shipping Information
                </h2>
                <div className="row">
                  <div className="col-lg-6">
                    <div className="accordion__container">
                      <div className="accordion__items">
                        <h2 className="accordion__items--title">
                          <button
                            className="faq__accordion--btn accordion__items--button"
                            onClick={() => toggleAccordion(0)}
                            aria-expanded={openIndex === 0}
                          >
                            What Shipping Methods Are Available?
                            <svg
                              className={`accordion__items--button__icon ${
                                openIndex === 0 ? "open" : ""
                              }`}
                              xmlns="http://www.w3.org/2000/svg"
                              width="20.355"
                              height="13.394"
                              viewBox="0 0 512 512"
                            >
                              <path
                                d="M98 190.06l139.78 163.12a24 24 0 0036.44 0L414 190.06c13.34-15.57 2.28-39.62-18.22-39.62h-279.6c-20.5 0-31.56 24.05-18.18 39.62z"
                                fill="currentColor"
                              />
                            </svg>
                          </button>
                        </h2>
                        {openIndex === 0 && (
                          <div className="accordion__items--body">
                            <p className="accordion__items--body__desc">
                              There are three delivery methods: Last Mile,
                              Dropoff Location, and Pickup from the Group
                              Leader. Each has its own features and charges.
                            </p>
                          </div>
                        )}
                      </div>
                      <div className="accordion__items">
                        <h2 className="accordion__items--title">
                          <button
                            className="faq__accordion--btn accordion__items--button"
                            onClick={() => toggleAccordion(1)}
                            aria-expanded={openIndex === 1}
                          >
                            How Long Will it Take To Get My Package?
                            <svg
                              className={`accordion__items--button__icon ${
                                openIndex === 1 ? "open" : ""
                              }`}
                              xmlns="http://www.w3.org/2000/svg"
                              width="20.355"
                              height="13.394"
                              viewBox="0 0 512 512"
                            >
                              <path
                                d="M98 190.06l139.78 163.12a24 24 0 0036.44 0L414 190.06c13.34-15.57 2.28-39.62-18.22-39.62h-279.6c-20.5 0-31.56 24.05-18.18 39.62z"
                                fill="currentColor"
                              />
                            </svg>
                          </button>
                        </h2>
                        {openIndex === 1 && (
                          <div className="accordion__items--body">
                            <p className="accordion__items--body__desc">
                              Orders are typically delivered within 24 hours
                              after confirmation.
                            </p>
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                  <div className="col-lg-6"></div>
                </div>
              </div>
              <div
                className="face__step one border-bottom"
                id="accordionExample2"
              >
                <h3 className="face__step--title mb-30">Payment Information</h3>
                <div className="row">
                  <div className="col-lg-6">
                    <div className="accordion__container">
                      <div className="accordion__items">
                        <h2 className="accordion__items--title">
                          <button
                            className="faq__accordion--btn accordion__items--button"
                            onClick={() => toggleAccordion(6)}
                            aria-expanded={openIndex === 6}
                          >
                            What payment types can I use?
                            <svg
                              className={`accordion__items--button__icon ${
                                openIndex === 6 ? "open" : ""
                              }`}
                              xmlns="http://www.w3.org/2000/svg"
                              width="20.355"
                              height="13.394"
                              viewBox="0 0 512 512"
                            >
                              <path
                                d="M98 190.06l139.78 163.12a24 24 0 0036.44 0L414 190.06c13.34-15.57 2.28-39.62-18.22-39.62h-279.6c-20.5 0-31.56 24.05-18.18 39.62z"
                                fill="currentColor"
                              />
                            </svg>
                          </button>
                        </h2>
                        {openIndex === 6 && (
                          <div className="accordion__items--body">
                            <p className="accordion__items--body__desc">
                              you can use any local bank mobile banking system
                            </p>
                          </div>
                        )}
                      </div>

                      <div className="accordion__items">
                        <h2 className="accordion__items--title">
                          <button
                            className="faq__accordion--btn accordion__items--button"
                            onClick={() => toggleAccordion(8)}
                            aria-expanded={openIndex === 8}
                          >
                            Can I cancel an order after placing it?
                            <svg
                              className={`accordion__items--button__icon ${
                                openIndex === 8 ? "open" : ""
                              }`}
                              xmlns="http://www.w3.org/2000/svg"
                              width="20.355"
                              height="13.394"
                              viewBox="0 0 512 512"
                            >
                              <path
                                d="M98 190.06l139.78 163.12a24 24 0 0036.44 0L414 190.06c13.34-15.57 2.28-39.62-18.22-39.62h-279.6c-20.5 0-31.56 24.05-18.18 39.62z"
                                fill="currentColor"
                              />
                            </svg>
                          </button>
                        </h2>
                        {openIndex === 8 && (
                          <div className="accordion__items--body">
                            <p className="accordion__items--body__desc">
                              Answer: You can cancel an order, but it must be
                              done before the provider accepts it.
                            </p>
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                  <div className="col-lg-6">
                    <div className="accordion__container">
                      <div className="accordion__items">
                        <h2 className="accordion__items--title">
                          <button
                            className="faq__accordion--btn accordion__items--button"
                            onClick={() => toggleAccordion(9)}
                            aria-expanded={openIndex === 9}
                          >
                            How can I track the status of my order?
                            <svg
                              className={`accordion__items--button__icon ${
                                openIndex === 9 ? "open" : ""
                              }`}
                              xmlns="http://www.w3.org/2000/svg"
                              width="20.355"
                              height="13.394"
                              viewBox="0 0 512 512"
                            >
                              <path
                                d="M98 190.06l139.78 163.12a24 24 0 0036.44 0L414 190.06c13.34-15.57 2.28-39.62-18.22-39.62h-279.6c-20.5 0-31.56 24.05-18.18 39.62z"
                                fill="currentColor"
                              />
                            </svg>
                          </button>
                        </h2>
                        {openIndex === 9 && (
                          <div className="accordion__items--body">
                            <p className="accordion__items--body__desc">
                              You can track your order status by going to the
                              "Orders" section in the app.
                            </p>
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </section>
        {/* faq page section end */}
        {/* Start shipping section */}
        <section className="shipping__section2 shipping__style3 section--padding pt-0">
          <div className="container">
            <div className="shipping__section2--inner shipping__style3--inner d-flex justify-content-between">
              <div className="shipping__items2 d-flex align-items-center">
                <div className="shipping__items2--icon">
                  <img src="assets/img/other/shipping1.png" alt="" />
                </div>
                <div className="shipping__items2--content">
                  <h2 className="shipping__items2--content__title h3">
                    Shipping
                  </h2>
                  <p className="shipping__items2--content__desc">
                    From handpicked sellers
                  </p>
                </div>
              </div>
              <div className="shipping__items2 d-flex align-items-center">
                <div className="shipping__items2--icon">
                  <img src="assets/img/other/shipping2.png" alt="" />
                </div>
                <div className="shipping__items2--content">
                  <h2 className="shipping__items2--content__title h3">
                    Payment
                  </h2>
                  <p className="shipping__items2--content__desc">
                    From handpicked sellers
                  </p>
                </div>
              </div>
              <div className="shipping__items2 d-flex align-items-center">
                <div className="shipping__items2--icon">
                  <img src="assets/img/other/shipping3.png" alt="" />
                </div>
                <div className="shipping__items2--content">
                  <h2 className="shipping__items2--content__title h3">
                    Return
                  </h2>
                  <p className="shipping__items2--content__desc">
                    From handpicked sellers
                  </p>
                </div>
              </div>
              <div className="shipping__items2 d-flex align-items-center">
                <div className="shipping__items2--icon">
                  <img src="assets/img/other/shipping4.png" alt="" />
                </div>
                <div className="shipping__items2--content">
                  <h2 className="shipping__items2--content__title h3">
                    Support
                  </h2>
                  <p className="shipping__items2--content__desc">
                    From handpicked sellers
                  </p>
                </div>
              </div>
            </div>
          </div>
        </section>
        {/* End shipping section */}
      </main>
      <Footer />
    </>
  );
};

export default Faq;
